func (a *App) handleTrack(w http.ResponseWriter, r *http.Request) {
	if strings.ToUpper(r.Method) != strings.ToUpper(a.cfg.TrackMethod) {
		w.Header().Set("Allow", a.cfg.TrackMethod)
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	now := time.Now()

	tr, err := a.parseTrackRequest(r)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	if tr.Method == "" {
		tr.Method = r.Header.Get("X-Method")
	}
	if tr.Method == "" {
		tr.Method = "UNKNOWN"
	}

	if tr.Path == "" {
		tr.Path = r.Header.Get("X-Path")
	}
	if tr.Path == "" {
		tr.Path = "UNKNOWN"
	}

	if tr.User == "" {
		tr.User = r.Header.Get("X-User")
	}
	if tr.User == "" {
		tr.User = "anonymous"
	}

	if a.cfg.EnableRequestIDLabel {
		if tr.RequestID == "" {
			tr.RequestID = r.Header.Get("X-Request-Id")
		}
		if tr.RequestID == "" {
			tr.RequestID = r.Header.Get("X-Request-ID")
		}
		if tr.RequestID == "" {
			tr.RequestID = r.URL.Query().Get("request_id")
		}
	} else {
		tr.RequestID = ""
	}
	if tr.RequestID == "" {
		tr.RequestID = "none"
	}

	if tr.Status == 0 {
		if s := r.URL.Query().Get("status"); s != "" {
			if n, _ := strconv.Atoi(s); n > 0 {
				tr.Status = n
			}
		}
	}
	if tr.Status == 0 {
		tr.Status = 200
	}

	if tr.ClientIP == "" {
		tr.ClientIP = clientIPFromRequest(r)
	}
	if tr.ClientIP == "" {
		tr.ClientIP = "unknown"
	}

	extra := ""
	if len(tr.Extra) > 0 {
		extra = stableExtra(tr.Extra)
	} else {
		extra = r.URL.Query().Get("extra")
	}
	if extra == "" {
		extra = "none"
	}

	user := a.normalizeLabel("user", tr.User)
	req := a.normalizeLabel("request", tr.RequestID)
	method := a.normalizeLabel("method", strings.ToUpper(tr.Method))
	path := a.normalizeLabel("path", tr.Path)
	status := a.normalizeLabel("status", strconv.Itoa(tr.Status))
	clientIP := a.normalizeLabel("client_ip", tr.ClientIP)
	extra = a.normalizeLabel("extra", extra)

	key := SeriesKey{
		User:     user,
		Request:  req,
		Method:   method,
		Path:     path,
		Status:   status,
		ClientIP: clientIP,
		Extra:    extra,
	}

	labelValues := []string{user, req, method, path, status, clientIP, extra}

	entry, created, ok := a.store.GetOrCreate(key, labelValues, now)
	if !ok {
		a.metrics.seriesRejected.Inc()
		http.Error(w, "series limit reached", http.StatusTooManyRequests)
		return
	}
	if created {
		a.metrics.seriesAdded.Inc()
		a.metrics.activeSeries.Set(float64(a.store.SnapshotSize()))
	}

	a.metrics.inflight.WithLabelValues(entry.labelValues...).Inc()
	start := time.Now()

	dur := tr.DurationS
	if dur <= 0 {
		dur = time.Since(start).Seconds()
	}
	if math.IsNaN(dur) || math.IsInf(dur, 0) || dur < 0 {
		dur = 0
	}

	a.metrics.requestsTotal.WithLabelValues(entry.labelValues...).Inc()
	a.metrics.requestDuration.WithLabelValues(entry.labelValues...).Observe(dur)

	if tr.ReqBytes > 0 {
		a.metrics.requestBytes.WithLabelValues(entry.labelValues...).Observe(float64(tr.ReqBytes))
	}
	if tr.ResBytes > 0 {
		a.metrics.responseBytes.WithLabelValues(entry.labelValues...).Observe(float64(tr.ResBytes))
	}

	a.metrics.inflight.WithLabelValues(entry.labelValues...).Dec()
	a.store.MarkSeen(key, time.Now())

	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]any{
		"ok":            true,
		"created_series": created,
	})
}

func (a *App) parseTrackRequest(r *http.Request) (TrackRequest, error) {
	var tr TrackRequest

	ct := r.Header.Get("Content-Type")
	if strings.Contains(ct, "application/json") {
		dec := json.NewDecoder(http.MaxBytesReader(nil, r.Body, 1<<20))
		dec.DisallowUnknownFields()
		if err := dec.Decode(&tr); err != nil {
			return tr, fmt.Errorf("invalid json: %v", err)
		}
		return tr, nil
	}

	q := r.URL.Query()
	tr.User = q.Get("user")
	tr.RequestID = q.Get("request_id")
	tr.Method = q.Get("method")
	tr.Path = q.Get("path")
	if s := q.Get("status"); s != "" {
		n, err := strconv.Atoi(s)
		if err != nil {
			return tr, fmt.Errorf("invalid status: %v", err)
		}
		tr.Status = n
	}
	if s := q.Get("duration_seconds"); s != "" {
		f, err := strconv.ParseFloat(s, 64)
		if err != nil {
			return tr, fmt.Errorf("invalid duration_seconds: %v", err)
		}
		tr.DurationS = f
	}
	if s := q.Get("request_bytes"); s != "" {
		n, err := strconv.ParseInt(s, 10, 64)
		if err != nil {
			return tr, fmt.Errorf("invalid request_bytes: %v", err)
		}
		tr.ReqBytes = n
	}
	if s := q.Get("response_bytes"); s != "" {
		n, err := strconv.ParseInt(s, 10, 64)
		if err != nil {
			return tr, fmt.Errorf("invalid response_bytes: %v", err)
		}
		tr.ResBytes = n
	}
	tr.ClientIP = q.Get("client_ip")

	extra := q.Get("extra")
	if extra != "" {
		tr.Extra = map[string]string{"q": extra}
	}
	return tr, nil
}

func stableExtra(m map[string]string) string {
	if len(m) == 0 {
		return ""
	}
	// stable but lightweight: hash the canonical JSON
	b, _ := json.Marshal(m)
	sum := sha256.Sum256(b)
	return "sha256:" + hex.EncodeToString(sum[:])
}

func (a *App) normalizeLabel(name, v string) string {
	if v == "" {
		return "none"
	}
	if !a.cfg.AllowUnsafeLabels {
		v = strings.TrimSpace(v)
		v = a.sanitizeRe.ReplaceAllString(v, "_")
		v = strings.Join(strings.Fields(v), " ")
		if v == "" {
			v = "none"
		}
	}

	max := a.cfg.MaxLabelLen
	if max > 0 && len(v) > max {
		if a.cfg.HashLongLabels {
			return a.hashLabel(name, v)
		}
		return v[:max]
	}
	return v
}

func (a *App) hashLabel(name, v string) string {
	salt := a.cfg.HashSalt
	if salt == "" {
		// stable per process but not secret; still avoids raw value exposure in metrics.
		h := fnv.New64a()
		_, _ = h.Write([]byte(name))
		_, _ = h.Write([]byte{0})
		_, _ = h.Write([]byte(v))
		return fmt.Sprintf("fnv64a:%x", h.Sum64())
	}
	sum := sha256.Sum256([]byte(salt + "\x00" + name + "\x00" + v))
	return "sha256:" + hex.EncodeToString(sum[:])
}

func clientIPFromRequest(r *http.Request) string {
	xff := r.Header.Get("X-Forwarded-For")
	if xff != "" {
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			ip := strings.TrimSpace(parts[0])
			if ip != "" {
				return ip
			}
		}
	}
	xri := strings.TrimSpace(r.Header.Get("X-Real-IP"))
	if xri != "" {
		return xri
	}
	host, _, err := net.SplitHostPort(strings.TrimSpace(r.RemoteAddr))
	if err == nil && host != "" {
		return host
	}
	if r.RemoteAddr != "" {
		return r.RemoteAddr
	}
	return ""
}

type ctxKey string

const requestIDKey ctxKey = "request_id"

func withRequestID(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		rid := r.Header.Get("X-Request-Id")
		if rid == "" {
			rid = r.Header.Get("X-Request-ID")
		}
		if rid == "" {
			rid = strconv.FormatInt(time.Now().UnixNano(), 10)
		}
		ctx := context.WithValue(r.Context(), requestIDKey, rid)
		w.Header().Set("X-Request-Id", rid)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

func withTimeouts(next http.Handler, timeout time.Duration) http.Handler {
	if timeout <= 0 {
		return next
	}
	return http.TimeoutHandler(next, timeout, `{"error":"timeout"}`)
}